// Recommended fix for INC-007: author uppercase text in DOM
<Badge
  color={status === 'up' ? 'green' : 'red'}
  radius="xl"
  variant={colorScheme === 'dark' ? 'filled' : 'light'}
>
  {status.toUpperCase()}
</Badge>

// In your CSS/theme:
// pre { font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace; }

<Card>
  <Group justify="flex-end">
    <CopyButton value={configYaml} />
  </Group>
  <pre>
    <code
      className="language-yaml"
      ref={(el) => el && hljs.highlightElement(el)}
    >
      {configYaml}
    </code>
  </pre>
</Card>

